const tx = $items('Create Transaction')[0].json;
const input = $items('Set Manual Active Call')[0].json;
const normalizedQuery = `search_query: ${tx.user_query.replace(/\s+/g, ' ').trim()}`;
return [{
  json: {
    ...tx,
    normalized_query: normalizedQuery,
    qdrant_collection: input.qdrant_collection || 'tpm_unite_history',
    min_result_count: Number(input.min_result_count ?? 3),
    retrieval_score_threshold: Number(input.retrieval_score_threshold ?? 0.55)
  }
}];

const tx = $items('Create Transaction')[0].json;
const normalized = $items('Normalize Query')[0].json;
const response = $json;
const statusCode = response.statusCode ?? response.status ?? 0;
const result = response.body?.result ?? {};
const pointsCount = Number(result.points_count ?? result.pointsCount ?? result.vectors_count ?? 0);
const collectionExists = statusCode >= 200 && statusCode < 300 && !!response.body?.result;
const collectionReady = collectionExists && pointsCount > 0;
let retrievalDecision = 'collection_ready_for_embedding';
let nextStatus = 'retrieving';
let nextRetrievalStatus = 'not_started';
let refusalReason = null;
let phase2Result = 'ready_for_embedding_and_vector_search';

if (!collectionExists) {
  retrievalDecision = 'qdrant_collection_missing';
  nextStatus = 'refused';
  nextRetrievalStatus = 'no_context';
  refusalReason = 'qdrant_collection_missing';
  phase2Result = 'refused_missing_qdrant_collection';
} else if (!collectionReady) {
  retrievalDecision = 'qdrant_collection_empty';
  nextStatus = 'refused';
  nextRetrievalStatus = 'no_context';
  refusalReason = 'qdrant_collection_empty';
  phase2Result = 'refused_empty_qdrant_collection';
}

return [{
  json: {
    transaction_id: tx.transaction_id,
    user_query: tx.user_query,
    normalized_query: normalized.normalized_query,
    qdrant_collection: normalized.qdrant_collection,
    min_result_count: normalized.min_result_count,
    retrieval_score_threshold: normalized.retrieval_score_threshold,
    qdrant_status_code: statusCode,
    collection_exists: collectionExists,
    points_count: pointsCount,
    collection_ready: collectionReady,
    retrieval_decision: retrievalDecision,
    next_status: nextStatus,
    next_retrieval_status: nextRetrievalStatus,
    refusal_reason: refusalReason,
    phase_2_result: phase2Result
  }
}];
